const copy = {
  en: {
    report: 'Website UX Audit', snapshot: 'Executive snapshot', scope: 'Scope & methodology', legend: 'Severity & category legend', scorecard: 'Scorecard', roadmap: 'Priority roadmap', conclusion: 'Conclusion', closing: 'Thank you',
    score: 'UX Health Score', provisional: 'Provisional', working: 'What is working', attention: 'What needs attention now', included: 'Included scope', excluded: 'Exclusions', limitation: 'Limitation', methodology: 'Assessment method',
    severity: 'Severity', categories: 'Issue categories', distribution: 'Finding distribution', coverage: 'Coverage notes', fixNow: 'Fix now', fixNext: 'Fix next', enhanceLater: 'Enhance later',
    observed: 'What we observed', impact: 'Why it matters', recommendation: 'Recommendation', evidence: 'Evidence', blocked: 'Evidence image is unavailable for publication', capture: 'Capture context', validation: 'Suggested validation', draft: 'DRAFT',
    workingDefault: 'Public journeys and visible service information were available for review.', conclusionText: 'Prioritize the immediate roadmap items, then validate the remediated journey with representative users and accessibility checks.',
  },
  ar: {
    report: 'تدقيق تجربة المستخدم للموقع الإلكتروني', snapshot: 'الملخص التنفيذي', scope: 'النطاق والمنهجية', legend: 'مقياس الأولوية وتصنيفات الملاحظات', scorecard: 'بطاقة تقييم التجربة', roadmap: 'خارطة أولويات التحسين', conclusion: 'الخلاصة', closing: 'شكراً لكم',
    score: 'تقييم صحة التجربة', provisional: 'مبدئي', working: 'ما يعمل بشكل جيد', attention: 'ما يحتاج إلى اهتمام فوري', included: 'النطاق المشمول', excluded: 'الاستثناءات', limitation: 'القيود', methodology: 'منهجية التقييم',
    severity: 'مقياس الأولوية', categories: 'تصنيفات الملاحظات', distribution: 'توزيع الملاحظات', coverage: 'ملاحظات التغطية', fixNow: 'معالجة فورية', fixNext: 'التحسينات التالية', enhanceLater: 'تحسينات لاحقة',
    observed: 'ما لاحظناه', impact: 'لماذا يهم ذلك', recommendation: 'التوصية', evidence: 'الدليل', blocked: 'صورة الدليل غير متاحة للنشر', capture: 'سياق الالتقاط', validation: 'التحقق المقترح', draft: 'مسودة',
    workingDefault: 'كانت الرحلات العامة ومعلومات الخدمة الظاهرة متاحة للمراجعة.', conclusionText: 'ابدأ بعناصر المعالجة الفورية، ثم تحقق من الرحلة بعد الإصلاح مع مستخدمين ممثلين وفحص إمكانية الوصول.',
  },
};

const severityInfo = {
  critical: { rank: 1, en: 'Critical', ar: 'حرجة', definition: { en: 'Immediate risk to a core task, trust, or accessibility.', ar: 'تؤثر مباشرة على مهمة أساسية أو الثقة أو إمكانية الوصول.' } },
  high: { rank: 2, en: 'High', ar: 'عالية', definition: { en: 'Significant friction in a valuable journey.', ar: 'تسبب عائقاً مهماً في رحلة مستخدم ذات قيمة.' } },
  medium: { rank: 3, en: 'Medium', ar: 'متوسطة', definition: { en: 'Noticeable friction; a workaround exists.', ar: 'تسبب احتكاكاً ملحوظاً مع وجود بديل ممكن.' } },
  low: { rank: 4, en: 'Low', ar: 'منخفضة', definition: { en: 'Limited-impact clarity or polish improvement.', ar: 'تحسين محدود الأثر في الوضوح أو الصقل.' } },
};
const categories = { usability: ['Usability', 'سهولة الاستخدام'], information_architecture: ['Information Architecture', 'هندسة المعلومات'], interface_visual_design: ['Interface & Visual Design', 'تصميم الواجهة والتصميم المرئي'], content_microcopy: ['Content & Microcopy', 'المحتوى والكتابة المصغرة'], trust_credibility: ['Trust & Credibility', 'الثقة والمصداقية'], forms_data_entry: ['Forms & Data Entry', 'النماذج وإدخال البيانات'], search_discovery: ['Search & Discovery', 'البحث والاكتشاف'], accessibility: ['Accessibility', 'إمكانية الوصول'], technical_bug: ['Technical / Bug', 'خلل تقني'] };
const esc = (value = '') => String(value).replace(/[&<>'"]/g, char => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', "'": '&#39;', '"': '&quot;' }[char]));
const text = (finding, field, locale) => locale === 'ar' ? finding.arabic?.[field] || 'الترجمة العربية مطلوبة قبل النشر' : finding[field] || '';
const technical = value => `<span class="technical-token" dir="ltr">${esc(value)}</span>`;
const severity = (finding, locale) => { const value = severityInfo[finding.severity] || severityInfo.low; return `<span class="severity severity-${finding.severity || 'low'}"><b>${value.rank}</b> ${value[locale]}</span>`; };
const list = (items, empty = '—') => items?.length ? `<ul>${items.map(item => `<li>${esc(item)}</li>`).join('')}</ul>` : `<p>${empty}</p>`;
const findingsBy = (findings, predicate) => findings.filter(predicate);
function evidencePath(value) { if (typeof value === 'string') { const trimmed = value.trim(); if (!trimmed) return ''; try { return evidencePath(JSON.parse(trimmed)); } catch { return trimmed; } } return value && typeof value === 'object' ? evidencePath(value.path || value.url || value.href) : ''; }
function assessmentEntries(audit) { const value = audit.assessments || []; return Array.isArray(value) ? value : Object.entries(value).map(([id, status]) => ({ id, status })); }
function score(audit) { const persisted = audit.assessmentSummary?.score; const applicable = assessmentEntries(audit).filter(item => ['pass', 'partial', 'issue'].includes(item.status)).length; return audit.templateId && !Number.isFinite(persisted) && applicable === 0 ? null : (Number.isFinite(persisted) ? persisted : 0); }
function scoreMarkup(audit, locale) { const value = score(audit); return value === null ? (locale === 'ar' ? 'غير مقيّم' : 'Not scored') : `${value}<small>/100</small>`; }
function assessmentCoverage(audit) { const entries = assessmentEntries(audit); const total = entries.length; const verified = Number.isFinite(audit.assessmentSummary?.scoredCheckpoints) ? audit.assessmentSummary.scoredCheckpoints : entries.filter(item => ['pass', 'partial', 'issue'].includes(item.status)).length; return `${verified} / ${total || verified}`; }
function evidence(finding, labels) { const item = finding.evidence || {}; const annotated = evidencePath(item.annotatedImage); const source = !item.evidencePending && annotated || evidencePath(item.imageUrl) || evidencePath(item.image); if (source) return `<figure class="evidence-canvas finding-evidence"><img src="${esc(source)}" alt="${esc(item.alt || item.description || '')}"><figcaption>${esc(item.description || '')}</figcaption></figure>`; return `<figure class="finding-evidence publication-blocked"><div aria-label="${labels.blocked}"><strong>${labels.evidence}</strong><span>${labels.blocked}</span></div><figcaption>${esc(item.description || '')}</figcaption></figure>`; }
function roadmapGroup(heading, group, locale) { return `<section class="roadmap-group"><h3>${heading}</h3>${group.length ? group.map(item => `<a href="#${esc(item.id)}" class="roadmap-item">${severity(item, locale)} ${technical(item.id)}<strong>${esc(text(item, 'title', locale))}</strong><small>${esc(item.page || '')} · ${esc(item.journey || '')}</small></a>`).join('') : '<p>—</p>'}</section>`; }

export function renderReport(audit, locale = 'en') {
  const language = locale === 'ar' ? 'ar' : 'en'; const l = copy[language];
  const findings = (audit.findings || []).filter(finding => !finding.excludedFromPublication);
  const criticalHigh = findingsBy(findings, item => ['critical', 'high'].includes(item.severity));
  const medium = findingsBy(findings, item => item.severity === 'medium'); const low = findingsBy(findings, item => !['critical', 'high', 'medium'].includes(item.severity));
  const notVerified = assessmentEntries(audit).filter(item => item.status === 'not_verified').length || audit.assessmentSummary?.notVerified || 0;
  const categoryNames = [...new Set(findings.map(item => (categories[item.category] || [item.category || '—'])[language === 'ar' ? 1 : 0]))];
  const counts = Object.fromEntries(Object.keys(severityInfo).map(key => [key, findingsBy(findings, item => item.severity === key).length]));
  return `<article class="report-document" lang="${language}" dir="${language === 'ar' ? 'rtl' : 'ltr'}">
    <div class="report-toolbar no-print"><span class="report-brand" aria-label="UXM Audit">UXM <b>Audit</b></span><a href="#roadmap">${l.roadmap}</a><button type="button" data-export-pdf>${language === 'ar' ? 'تقرير PDF' : 'PDF report'}</button></div>
    <section class="cover-page print-page"><div class="cover-grid"><div><p class="wordmark">UXM</p><p class="eyebrow">${l.report} · 2026</p><h1>${esc(audit.client || '')}</h1><p class="cover-lede">${language === 'ar' ? 'مراجعة مركزة لتجربة المستخدم، سهولة الوصول إلى المحتوى، وجاهزية التحويل.' : 'A focused review of user experience, discoverability, and conversion readiness.'}</p></div><div class="cover-meta"><p><span>Website URL</span>${technical(audit.url || '')}</p><p><span>Report reference</span>${technical(audit.id || '')}</p><span class="watermark">${l.draft}</span></div></div></section>
    <section class="snapshot-page print-page"><div class="page-head"><p class="section-number">01</p><p>${l.snapshot}</p></div><div class="snapshot-grid"><div class="hero-score"><strong>${scoreMarkup(audit, language)}</strong><span>${l.score}</span>${notVerified ? `<em>${l.provisional}</em>` : ''}</div><div class="snapshot-panel"><h2>${l.working}</h2><p>${l.workingDefault}</p><p class="snapshot-stat">${assessmentCoverage(audit)} <span>${language === 'ar' ? 'معيار في التقييم' : 'checks in scope'}</span></p></div><div class="snapshot-panel attention"><h2>${l.attention}</h2>${list(criticalHigh.map(item => `${item.id} — ${text(item, 'title', language)}`))}</div></div><div class="snapshot-bottom"><p>${language === 'ar' ? 'النتيجة تجمع سهولة إتمام المهمة، وضوح المحتوى، والثقة ضمن الرحلات العامة المتاحة.' : 'The score consolidates task completion, content clarity, and trust across the public journeys reviewed.'}</p><div>${Object.entries(counts).map(([key, value]) => `<span>${severity({ severity: key }, language)} <b>${value}</b></span>`).join('')}</div></div></section>
    <section class="methodology-page print-page"><div class="page-head"><p class="section-number">02</p><p>${l.scope}</p></div><div class="methodology-grid"><div class="method-card"><p class="eyebrow">01</p><h2>${l.included}</h2>${list(audit.scope?.included || (typeof audit.scope === 'string' ? [audit.scope] : []))}<h3>${l.excluded}</h3>${list(audit.scope?.excluded)}</div><div class="method-card accent"><p class="eyebrow">02</p><h2>${l.methodology}</h2><p>${esc(audit.assessmentSummary?.method || (language === 'ar' ? 'مجتاز = 1، جزئي = 0.5، ملاحظة = 0؛ لم يتم التحقق منه مستبعد من النتيجة.' : 'Pass = 1, Partial = 0.5, Issue = 0; Not verified is excluded from scoring.'))}</p><h3>${l.limitation}</h3><p>${esc(audit.scope?.limitation || (notVerified ? `${notVerified} ${language === 'ar' ? 'حالات لم يتم التحقق منها.' : 'states were not verified.'}` : '—'))}</p></div><aside class="method-note"><strong>${notVerified}</strong><span>${language === 'ar' ? 'حالات غير متحقق منها' : 'unverified states'}</span></aside></div></section>
    <section class="legend-page print-page"><div class="page-head"><p class="section-number">03</p><p>${l.legend}</p></div><div class="legend-layout"><div><h2>${l.severity}</h2><div class="severity-legend">${Object.entries(severityInfo).map(([name, value]) => `<div class="severity severity-${name}"><b>${value.rank}</b><strong>${value[language]}</strong><span>${value.definition[language]}</span></div>`).join('')}</div></div><aside class="category-rail"><p class="eyebrow">${l.categories}</p><ol>${categoryNames.map(name => `<li>${esc(name)}</li>`).join('') || '<li>—</li>'}</ol><p>${language === 'ar' ? 'يربط المقياس بين الأولوية والأثر المحتمل على إنجاز المهمة أو الثقة أو إمكانية الوصول.' : 'The scale ties priority to potential impact on task completion, trust, or accessibility.'}</p></aside></div></section>
    <section id="roadmap" class="scorecard-roadmap-page print-page"><div class="page-head"><p class="section-number">04</p><p>${l.scorecard} &amp; ${l.roadmap}</p></div><div class="scorecard-roadmap-grid"><aside class="score-rail"><div class="hero-score"><strong>${scoreMarkup(audit, language)}</strong><span>${l.score}</span></div><h3>${l.coverage}</h3><p>${assessmentCoverage(audit)} ${language === 'ar' ? 'معيار تم تقييمه أو إدراجه في النطاق.' : 'checks assessed or included in the audit scope.'}</p><div class="distribution">${Object.keys(severityInfo).map(key => `<p>${severity({ severity: key }, language)} <b>${counts[key]}</b></p>`).join('')}</div></aside><div class="roadmap-list">${roadmapGroup(l.fixNow, criticalHigh, language)}${roadmapGroup(l.fixNext, medium, language)}${roadmapGroup(l.enhanceLater, low, language)}</div></div></section>
    ${findings.map((finding, index) => `<section id="${esc(finding.id)}" class="finding-page print-page"><header class="finding-head"><div><span>${technical(finding.id)}</span>${severity(finding, language)}</div><p>${esc(finding.page || '')} · ${esc(finding.journey || '')}</p><h2>${esc(text(finding, 'title', language))}</h2></header><div class="finding-layout">${evidence(finding, l)}<div class="finding-story"><section><h3>${l.observed}</h3><p>${esc(text(finding, 'observed', language))}</p></section><section><h3>${l.impact}</h3><p>${esc(text(finding, 'impact', language))}</p></section><section class="recommendation"><h3>${l.recommendation}</h3><p>${esc(text(finding, 'recommendation', language))}</p></section></div></div><footer>${l.capture}: ${esc(finding.evidence?.capture || '—')} <span>·</span> ${technical(finding.evidence?.url || audit.url || '')} <span>·</span> ${index + 1} / ${findings.length}</footer></section>`).join('')}
    <section class="conclusion-page print-page"><div class="page-head"><p class="section-number">05</p><p>${l.conclusion}</p></div><div class="conclusion-grid"><h2>${l.conclusionText}</h2><div><h3>${l.validation}</h3><p>${language === 'ar' ? 'اختبار قابلية الاستخدام للرحلة ذات الأولوية، قياس الإكمال، وإعادة فحص إمكانية الوصول بعد الإصلاح.' : 'Test the priority journey with users, measure completion, and re-check accessibility after implementation.'}</p></div></div></section>
    <section class="closing-page print-page"><p class="wordmark">UXM</p><div><p class="eyebrow">${l.report}</p><h2>${l.closing}</h2><p>${esc(audit.client || '')}</p><p>${technical(audit.id || '')}</p></div></section>
  </article>`;
}
